def.body:
{% if T == String %}
        read_string
      {% elsif T < Number %}
        buf = uninitialized T
        dtype = NativeType.for(T)
        read_raw(dtype, pointerof(buf))
        buf
      {% else %}
        {% raise("Unsupported attribute type: #{T}") %}
      {% end %}

{% if T == String %}
        write_string(value)
      {% elsif T < Number %}
        dtype = NativeType.for(T)
        write_raw(dtype, pointerof(value))
      {% else %}
        {% raise("Unsupported attribute type: #{T}") %}
      {% end %}

{% if T == String %}
        ds = build_string_dataset(path, data.size.to_u64, string_type: StringType.variable)
        ds.write_strings(data)
        TypedDataset(String).new(ds)
      {% else %}
        dims = [data.size.to_u64]
        ds = build_numeric_dataset(path, T, dims)
        ds.write(data)
        TypedDataset(T).new(ds)
      {% end %}

dims = shape.map(&.to_u64).to_a
resolved_opts = options || (
  build_options(chunk, compression, compression_level, shuffle, fletcher32, max_shape)
)
{% if T == String %}
        ds = build_string_dataset(path, dims, resolved_opts, string_type: StringType.variable)
        TypedDataset(String).new(ds)
      {% else %}
        ds = build_numeric_dataset(path, T, dims, resolved_opts)
        TypedDataset(T).new(ds)
      {% end %}

{% if T == Int8 %}
        LibHDF5.h5t_native_int8_g
      {% elsif T == UInt8 %}
        LibHDF5.h5t_native_uint8_g
      {% elsif T == Int16 %}
        LibHDF5.h5t_native_int16_g
      {% elsif T == UInt16 %}
        LibHDF5.h5t_native_uint16_g
      {% elsif T == Int32 %}
        LibHDF5.h5t_native_int32_g
      {% elsif T == UInt32 %}
        LibHDF5.h5t_native_uint32_g
      {% elsif T == Int64 %}
        LibHDF5.h5t_native_int64_g
      {% elsif T == UInt64 %}
        LibHDF5.h5t_native_uint64_g
      {% elsif T == Float32 %}
        LibHDF5.h5t_native_float_g
      {% elsif T == Float64 %}
        LibHDF5.h5t_native_double_g
      {% else %}
        {% raise("Unsupported HDF5 type: #{T}") %}
      {% end %}

{% if T == String %}
        raise Error.new("Partial string I/O not supported")
      {% else %}
        @dataset.read(T, selection)
      {% end %}

{% if T == String %}
        raise Error.new("Partial string I/O not supported")
      {% else %}
        @dataset.write(data, selection)
      {% end %}

{% if T == String %}
        raise Error.new("Slice write not supported for String datasets")
      {% else %}
        @dataset.write(data)
      {% end %}
